div.script:
// 
(async function() {
  // FIX: Added the missing closing quote and base URL
  const url = 'https://cdn.jsdelivr.net/gh/rainS-IM/BPLGames@main/BPLPremium.html';
  const baseUrl = 'https://cdn.jsdelivr.net/gh/rainS-IM/BPLGames@main/';
  const frame = document.getElementById('fm');

  try {
    const res = await fetch(url);
    if (!res.ok) throw new Error("Network Response Fail");
    const text = await res.text();

    // Safari fix: Use srcdoc with a <base> tag to ensure 
    // relative links in your HTML still work.
    frame.srcdoc = `<html><head><base href="${baseUrl}"></head><body>${text}</body></html>`;

  } catch(e) {
    console.error('Loader error:', e);
    // Show error on screen if it fails
    document.body.innerHTML = `<div style="color:red; font-family:sans-serif; padding:20px;">Load Error: ${e.message}</div>`;
  }
})();
//
